package com.example.health_app.network

import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

private const val BASE_URL = "https://mocki.io/v1/"

data class HeartRateResponse(val value: Int)
data class SpO2Response(val value: Int)
data class TemperatureResponse(val value: Double)

interface MockHealthApi {
    @GET("heartrate")
    suspend fun getHeartRate(): HeartRateResponse

    @GET("spo2")
    suspend fun getSpO2(): SpO2Response

    @GET("temperature")
    suspend fun getTemperature(): TemperatureResponse
}

object MockHealthApiProvider {
    val api: MockHealthApi by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(MockHealthApi::class.java)
    }
}

package com.example.health_app.network

import android.content.Context
import android.hardware.Sensor
import android.hardware.SensorEvent
import android.hardware.SensorEventListener
import android.hardware.SensorManager
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import kotlinx.coroutines.withTimeoutOrNull
import kotlin.coroutines.resume
import kotlin.random.Random

class SensorRepository(
	context: Context,
	private val api: MockHealthApi = MockHealthApiProvider.api
) {
	private val sensorManager = context.getSystemService(Context.SENSOR_SERVICE) as SensorManager

	fun hasHeartRateSensor(): Boolean {
		return sensorManager.getDefaultSensor(Sensor.TYPE_HEART_RATE) != null
	}

	suspend fun readHeartRateFromSensor(): Int? {
		val sensor = sensorManager.getDefaultSensor(Sensor.TYPE_HEART_RATE) ?: return null

		return withTimeoutOrNull(4000L) {
			suspendCancellableCoroutine { continuation ->
				val listener = object : SensorEventListener {
					override fun onSensorChanged(event: SensorEvent?) {
						val value = event?.values?.firstOrNull()?.toInt()
						if (value != null && value > 0 && continuation.isActive) {
							sensorManager.unregisterListener(this)
							continuation.resume(value)
						}
					}

					override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) = Unit
				}

				sensorManager.registerListener(listener, sensor, SensorManager.SENSOR_DELAY_NORMAL)
				continuation.invokeOnCancellation {
					sensorManager.unregisterListener(listener)
				}
			}
		}
	}

	suspend fun readHeartRateFromApi(): Int = withContext(Dispatchers.IO) {
		runCatching { api.getHeartRate().value }.getOrElse { Random.nextInt(60, 101) }
	}

	suspend fun readSpO2FromApi(): Int = withContext(Dispatchers.IO) {
		runCatching { api.getSpO2().value }.getOrElse { Random.nextInt(94, 100) }
	}

	suspend fun readTemperatureFromApi(): Double = withContext(Dispatchers.IO) {
		runCatching { api.getTemperature().value }.getOrElse { Random.nextDouble(36.0, 37.8) }
	}
}

package com.example.health_app.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.navArgument
import com.example.health_app.ui.screens.PodrobnostiMeritveScreen
import com.example.health_app.ui.screens.SeznamMeritevScreen
import com.example.health_app.ui.screens.VnosMeritveScreen
import com.example.health_app.viewmodel.MeritevViewModel

object Routes {
    const val VNOS = "vnos"
    const val SEZNAM = "seznam"
    const val PODROBNOSTI = "podrobnosti"
}

@Composable
fun NavGraph(
    navController: NavHostController,
    viewModel: MeritevViewModel
) {
    NavHost(
        navController = navController,
        startDestination = Routes.VNOS
    ) {
        // View 1 – Input form (new or edit)
        composable(
            route = "${Routes.VNOS}?meritevId={meritevId}",
            arguments = listOf(
                navArgument("meritevId") {
                    type = NavType.IntType
                    defaultValue = -1
                }
            )
        ) { backStackEntry ->
            val meritevId = backStackEntry.arguments?.getInt("meritevId") ?: -1
            VnosMeritveScreen(
                viewModel = viewModel,
                meritevId = if (meritevId == -1) null else meritevId,
                onNavigateToDetail = { id ->
                    navController.navigate("${Routes.PODROBNOSTI}/$id")
                },
                onNavigateToList = {
                    navController.navigate(Routes.SEZNAM)
                }
            )
        }

        // View 3 – Measurement list
        composable(route = Routes.SEZNAM) {
            SeznamMeritevScreen(
                viewModel = viewModel,
                onNavigateBack = {
                    navController.popBackStack()
                },
                onNavigateToDetail = { id ->
                    navController.navigate("${Routes.PODROBNOSTI}/$id")
                },
                onNavigateToEdit = { id ->
                    navController.navigate("${Routes.VNOS}?meritevId=$id")
                }
            )
        }

        // View 2 – Measurement details
        composable(
            route = "${Routes.PODROBNOSTI}/{meritevId}",
            arguments = listOf(
                navArgument("meritevId") {
                    type = NavType.IntType
                }
            )
        ) { backStackEntry ->
            val meritevId = backStackEntry.arguments?.getInt("meritevId") ?: return@composable
            PodrobnostiMeritveScreen(
                viewModel = viewModel,
                meritevId = meritevId,
                onNavigateBack = {
                    navController.popBackStack()
                },
                onNavigateToEdit = { id ->
                    navController.navigate("${Routes.VNOS}?meritevId=$id")
                }
            )
        }
    }
}

package com.example.health_app.ui.navigation

import androidx.compose.runtime.Composable
import androidx.compose.runtime.LaunchedEffect
import androidx.compose.runtime.getValue
import androidx.navigation.NavHostController
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.navArgument
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import com.example.health_app.ui.screens.AuthScreen
import com.example.health_app.ui.screens.PodrobnostiMeritveScreen
import com.example.health_app.ui.screens.SeznamMeritevScreen
import com.example.health_app.ui.screens.VnosMeritveScreen
import com.example.health_app.viewmodel.AuthViewModel
import com.example.health_app.viewmodel.MeritevViewModel

object Routes {
    const val AUTH = "auth"
    const val VNOS = "vnos"
    const val SEZNAM = "seznam"
    const val PODROBNOSTI = "podrobnosti"
}

@Composable
fun NavGraph(
    navController: NavHostController,
    viewModel: MeritevViewModel,
    authViewModel: AuthViewModel
) {
    val authState by authViewModel.uiState.collectAsStateWithLifecycle()
    val startDestination = if (authState.currentUser != null) Routes.VNOS else Routes.AUTH

    LaunchedEffect(authState.currentUser?.uid) {
        viewModel.setCurrentUser(authState.currentUser?.uid)
    }

    NavHost(
        navController = navController,
        startDestination = startDestination
    ) {
        composable(route = Routes.AUTH) {
            AuthScreen(
                authViewModel = authViewModel,
                onAuthSuccess = {
                    navController.navigate(Routes.VNOS) {
                        popUpTo(Routes.AUTH) { inclusive = true }
                    }
                }
            )
        }

        // View 1 – Input form (new or edit)
        composable(
            route = "${Routes.VNOS}?meritevId={meritevId}",
            arguments = listOf(
                navArgument("meritevId") {
                    type = NavType.IntType
                    defaultValue = -1
                }
            )
        ) { backStackEntry ->
            val meritevId = backStackEntry.arguments?.getInt("meritevId") ?: -1
            VnosMeritveScreen(
                viewModel = viewModel,
                meritevId = if (meritevId == -1) null else meritevId,
                onNavigateToDetail = { id ->
                    navController.navigate("${Routes.PODROBNOSTI}/$id")
                },
                onNavigateToList = {
                    navController.navigate(Routes.SEZNAM)
                }
            )
        }

        // View 3 – Measurement list
        composable(route = Routes.SEZNAM) {
            SeznamMeritevScreen(
                viewModel = viewModel,
                onNavigateBack = {
                    navController.popBackStack()
                },
                onSync = { viewModel.syncFromFirestore() },
                onLogout = {
                    authViewModel.logout()
                    navController.navigate(Routes.AUTH) {
                        popUpTo(0) { inclusive = true }
                    }
                },
                loggedInEmail = authState.currentUser?.email,
                onNavigateToDetail = { id ->
                    navController.navigate("${Routes.PODROBNOSTI}/$id")
                },
                onNavigateToEdit = { id ->
                    navController.navigate("${Routes.VNOS}?meritevId=$id")
                }
            )
        }

        // View 2 – Measurement details
        composable(
            route = "${Routes.PODROBNOSTI}/{meritevId}",
            arguments = listOf(
                navArgument("meritevId") {
                    type = NavType.IntType
                }
            )
        ) { backStackEntry ->
            val meritevId = backStackEntry.arguments?.getInt("meritevId") ?: return@composable
            PodrobnostiMeritveScreen(
                viewModel = viewModel,
                meritevId = meritevId,
                onNavigateBack = {
                    navController.popBackStack()
                },
                onNavigateToEdit = { id ->
                    navController.navigate("${Routes.VNOS}?meritevId=$id")
                }
            )
        }
    }
}

