                    } else if (srcniUtrip < 30 || srcniUtrip > 250) {
                        srcniUtripError = srcniUtripNapaka
                        isValid = false
                    }

                    val spO2 = spO2Text.toIntOrNull()
                    if (spO2 == null) {
                        spO2Error = neveljavenVnos
                        isValid = false
                    } else if (spO2 < 0 || spO2 > 100) {
                        spO2Error = spO2Napaka
                        isValid = false
                    }

                    val temperatura = temperaturaText.replace(",", ".").toDoubleOrNull()
                    if (temperatura == null) {
                        temperaturaError = neveljavenVnos
                        isValid = false
                    } else if (temperatura < 34.0 || temperatura > 42.0) {
                        temperaturaError = temperaturaNapaka
                        isValid = false
                    }

                    if (isValid) {
                        val meritev = Meritev(
                            id = meritevId ?: 0,
                            ime = ime.trim(),
                            priimek = priimek.trim(),
                            datum = datum,
                            srcniUtrip = srcniUtrip!!,
                            spO2 = spO2!!,
                            temperatura = temperatura!!
                        )
                        if (meritevId != null) {
                            viewModel.posodobi(meritev)
                        } else {
                            viewModel.vstavi(meritev) { id ->
                                newlyInsertedId = id
                                resetForm()
                            }
                        }
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.primary
                )
            ) {
                Text(stringResource(R.string.shrani_meritev))
            }

            Spacer(modifier = Modifier.height(12.dp))

            // List button
            OutlinedButton(
                onClick = onNavigateToList,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text(stringResource(R.string.btn_seznam_meritev))
            }
        }
    }

    // Date Picker Dialog
    if (showDatePicker) {
        val datePickerState = rememberDatePickerState(initialSelectedDateMillis = datum)
        DatePickerDialog(
            onDismissRequest = { showDatePicker = false },
            confirmButton = {
                TextButton(onClick = {
                    datePickerState.selectedDateMillis?.let {
                        datum = it
                    }
                    showDatePicker = false
                }) {
                    Text(stringResource(R.string.potrdi))
                }
            },
            dismissButton = {
                TextButton(onClick = { showDatePicker = false }) {
                    Text(stringResource(R.string.preklici))
                }
            }
        ) {
            DatePicker(state = datePickerState)
        }
    }
}

package com.example.health_app.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.health_app.data.AuthRepository
import com.google.firebase.auth.FirebaseUser
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class AuthUiState(
    val currentUser: FirebaseUser? = null,
    val isLoading: Boolean = false,
    val error: String? = null
)

class AuthViewModel(
    private val repository: AuthRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(AuthUiState(currentUser = repository.currentUser))
    val uiState: StateFlow<AuthUiState> = _uiState.asStateFlow()

    fun login(email: String, password: String) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            runCatching { repository.login(email.trim(), password) }
                .onSuccess { user ->
                    _uiState.update { it.copy(currentUser = user, isLoading = false) }
                }
                .onFailure { error ->
                    _uiState.update { it.copy(isLoading = false, error = error.localizedMessage) }
                }
        }
    }

    fun register(email: String, password: String) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            runCatching { repository.register(email.trim(), password) }
                .onSuccess { user ->
                    _uiState.update { it.copy(currentUser = user, isLoading = false) }
                }
                .onFailure { error ->
                    _uiState.update { it.copy(isLoading = false, error = error.localizedMessage) }
                }
        }
    }

    fun logout() {
        repository.logout()
        _uiState.value = AuthUiState()
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }

    fun setError(message: String) {
        _uiState.update { it.copy(error = message) }
    }
}

class AuthViewModelFactory(
    private val repository: AuthRepository
) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(AuthViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return AuthViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

